:global(:root) {
    --profile-overlay-opacity: 0.4;
}

.trophies {
    position: absolute;
    background: rgba(0, 0, 0, var(--profile-overlay-opacity));
}

.badges {
    position: absolute;
    max-width: 5rem;
    background: rgba(0, 0, 0, var(--profile-overlay-opacity));
}

.statsRow {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mantine-spacing-md);
    align-items: stretch;
}

.statCards {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mantine-spacing-md);
    flex: 0 0 auto;
}

.identity {
    flex: 1 1 28rem;
    min-width: 0;
    container-type: inline-size;
    display: flex;
    flex-direction: column;
}

.identityInner {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: var(--mantine-spacing-md);
}

.identityPhoto {
    width: 100%;
    aspect-ratio: 3 / 4;
}

@container (min-width: 26em) {
    .identityInner {
        display: grid;
        grid-template-columns: minmax(10rem, 22rem) minmax(14rem, 1fr);
        gap: var(--mantine-spacing-md);
        height: 100%;
    }

    .identityPhoto {
        width: 100%;
        height: 100%;
        aspect-ratio: unset;
    }

    .identityTable {
        align-self: start;
    }
}

