                                        <TableTh className={classes.tableHeader}>Joined</TableTh>
                                        <TableTd>{player.joined ? formatDate(player.joined) : 'N/A'}</TableTd>
                                    </TableTr>
                                    {!!isAdmin && !!playerData && !!onSendEmail && (
                                        <TableTr>
                                            <TableTh className={classes.tableHeader}>Email</TableTh>
                                            <TableTd>
                                                <EmailPlayerButton player={playerData} onSendEmail={onSendEmail} />
                                            </TableTd>
                                        </TableTr>
                                    )}
                                    <TableTr>
                                        <TableTh className={classes.tableHeader}>Last played</TableTh>
                                        <TableTd><GameDayLink gameDay={lastPlayed?.gameDay} /></TableTd>
                                    </TableTr>
                                    <TableTr>
                                        <TableTh className={classes.tableHeader}>Last won</TableTh>
                                        <TableTd><GameDayLink gameDay={lastWon?.gameDay} /></TableTd>
                                    </TableTr>
                                    {!!isAuthenticated && (
                                        <TableTr>
                                            <TableTh style={{ whiteSpace: 'nowrap' }}>Born</TableTh>
                                            <TableTd>{player.born}</TableTd>
                                        </TableTr>
                                    )}
                                </TableTbody>
                            </Table>
                        </Box>
                    </Box>
                </Paper>

                <Box className={classes.statCards}>
                    <PlayerResults player={player} year={year} record={record} />
                    <PlayerPositions player={player} year={year} record={record} />
                    <PlayerArse arse={arse} />
                </Box>
            </Box>

            <Paper shadow="xs" p="sm" withBorder>
                <Title order={3} mb="xs" w="100%" ta="center">History</Title>
                <Divider mb="xs" />
                <PlayerHeatmap data={history} year={year} />
            </Paper>
        </Flex>
    );
};

