import { EmailPlayerButton } from '@/components/EmailPlayerButton/EmailPlayerButton';
import { GameDayLink } from '@/components/GameDayLink/GameDayLink';
import { PlayerArse } from '@/components/PlayerArse/PlayerArse';
import { PlayerCard } from '@/components/PlayerCard/PlayerCard';
import { PlayerHeatmap } from '@/components/PlayerHeatmap/PlayerHeatmap';
import { PlayerLink } from '@/components/PlayerLink/PlayerLink';
import { PlayerPositions } from '@/components/PlayerPositions/PlayerPositions';
import { PlayerResults } from '@/components/PlayerResults/PlayerResults';
import { TitleWithYearDropdown } from '@/components/TitleWithYearDropdown/TitleWithYearDropdown';
import { formatDate } from '@/lib/dates';
import { PlayerDisplayType } from '@/services/Player';
import { ClubSupporterDataType, CountrySupporterDataType, PlayerDataEmailDisplayType, PlayerFormType } from '@/types';
import type { SendEmailProxy } from '@/types/actions/SendEmail';

import classes from './PlayerProfile.module.css';

export interface Props {
    player: PlayerDisplayType;
    introducedBy: PlayerDisplayType | null;
    year: number;
    history: PlayerFormType[];
    lastPlayed: PlayerFormType | null;
    lastWon: PlayerFormType | null;
    clubs: ClubSupporterDataType[];
    countries: CountrySupporterDataType[];
    arse: Partial<ArseType> | null;
    activeYears: number[];
    record: PlayerRecordType | null;
    trophies: Map<TableName, PlayerRecordType[]>;
    prevPlayer: PlayerDisplayType | null;
    nextPlayer: PlayerDisplayType | null;
    isAuthenticated?: boolean;
    isAdmin?: boolean;
    playerData?: PlayerDataEmailDisplayType | null;
    onSendEmail?: SendEmailProxy;
}

export const PlayerProfile = ({
    player,
    year,
    introducedBy,
    history,
    lastPlayed,
    lastWon,
    clubs,
    countries,
    arse,
    activeYears,
    record,
    trophies,
    prevPlayer,
    nextPlayer,
    isAuthenticated = false,
    isAdmin = false,
    playerData,
    onSendEmail,
}: Props) => {
    const navSlotWidth = '2rem';

    return (
        <Flex direction="column" gap="sm">
            <Group justify="space-between" gap="xs" mb="lg">
                <Box w={navSlotWidth} ta="center">
                    {prevPlayer ?
                        <PlayerLink player={prevPlayer} year={year} format="left-arrow" /> :
                        <Box data-testid="player-prev-placeholder" aria-hidden="true" w={navSlotWidth} />}
                </Box>
                <TitleWithYearDropdown order={1} title={player.name} year={year} validYears={activeYears} />
                <Box w={navSlotWidth} ta="center">
                    {nextPlayer ?
                        <PlayerLink player={nextPlayer} year={year} format="right-arrow" /> :
                        <Box data-testid="player-next-placeholder" aria-hidden="true" w={navSlotWidth} />}
                </Box>
            </Group>

            <Box className={classes.statsRow}>
                <Paper className={classes.identity} shadow="xs" p="sm" withBorder>
                    <Box className={classes.identityInner}>
                        <Box className={classes.identityPhoto}>
                            <PlayerCard
                                player={player}
                                clubs={clubs}
                                countries={countries}
                                trophies={trophies}
                            />
                        </Box>
                        <Box className={classes.identityTable}>
                            <Title order={2} mb="xs" w="100%" ta="center">Info</Title>
                            <Divider mb="xs" />
                            <Table
                                variant="vertical"
                                w="100%"
                                summary={`${player.name}'s player information`}
                            >
                                <TableTbody>
                                    {!!introducedBy && (
                                        <TableTr>
                                            <TableTh className={classes.tableHeader}>Introduced by</TableTh>
                                            <TableTd><PlayerLink player={introducedBy} year={year} /></TableTd>
                                        </TableTr>
                                    )}
                                    <TableTr>
                                        <TableTh className={classes.tableHeader}>Joined</TableTh>
                                        <TableTd>{player.joined ? formatDate(player.joined) : 'N/A'}</TableTd>
                                    </TableTr>
                                    {!!isAdmin && !!playerData && !!onSendEmail && (
                                        <TableTr>
                                            <TableTh className={classes.tableHeader}>Email</TableTh>
                                            <TableTd>
                                                <EmailPlayerButton player={playerData} onSendEmail={onSendEmail} />
                                            </TableTd>
                                        </TableTr>
                                    )}
                                    <TableTr>
                                        <TableTh className={classes.tableHeader}>Last played</TableTh>
                                        <TableTd><GameDayLink gameDay={lastPlayed?.gameDay} /></TableTd>
                                    </TableTr>
                                    <TableTr>
                                        <TableTh className={classes.tableHeader}>Last won</TableTh>
                                        <TableTd><GameDayLink gameDay={lastWon?.gameDay} /></TableTd>
                                    </TableTr>
                                    {!!isAuthenticated && (
                                        <TableTr>
                                            <TableTh className={classes.tableHeader}>Born</TableTh>
                                            <TableTd>{player.born}</TableTd>
                                        </TableTr>
                                    )}
                                </TableTbody>
                            </Table>
                        </Box>
                    </Box>
                </Paper>

                <Box className={classes.statCards}>
                    <PlayerResults player={player} year={year} record={record} />
                    <PlayerPositions player={player} year={year} record={record} />
                    <PlayerArse arse={arse} />
                </Box>
            </Box>

            <Paper shadow="xs" p="sm" withBorder>
                <Title order={2} mb="xs" w="100%" ta="center">History</Title>
                <Divider mb="xs" />
                <PlayerHeatmap data={history} year={year} />
            </Paper>
        </Flex>
    );
};

