                    <TableTr><TableTd>Attacking</TableTd><TableTd w="3rem">{arse.attacking ?? '-'}</TableTd></TableTr>
                    <TableTr><TableTd>Defending</TableTd><TableTd w="3rem">{arse.defending ?? '-'}</TableTd></TableTr>
                </TableTbody>
            </Table>
        </Paper>
    );
};

